function TeamCard({ member }) {
  const [photoSrc, setPhotoSrc] = useState(null);
  const inputRef = useRef();

  const handleFile = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => setPhotoSrc(ev.target.result);
    reader.readAsDataURL(file);
  };

  return (
    <div style={s.teamCard}>
      <div style={s.teamCardHeader}>
        <div>
          <div style={s.teamPhoto} onClick={() => inputRef.current.click()}>
            {photoSrc ? (
              <img src={photoSrc} alt={member.name} style={{ position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover", borderRadius: "50%" }} />
            ) : (
              <>
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#8C6B55" strokeWidth="1.5">
                  <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/>
                </svg>
                <span style={{ fontSize: 10, color: "#8C6B55", textAlign: "center", lineHeight: 1.3 }}>Add photo</span>
              </>
            )}
            <input ref={inputRef} type="file" accept="image/*" onChange={handleFile} style={{ display: "none" }} />
          </div>
          <div style={s.uploadHint}>Click to upload</div>
        </div>
        <div>
          <div style={s.teamName}>{member.name}</div>
          <div style={s.teamSat}>SAT: <strong style={s.teamSatStrong}>{member.sat}</strong> &nbsp;·&nbsp; {member.rank}</div>
        </div>
      </div>
      <div style={s.teamStats}>
        {member.stats.map((stat, i) => (
          <div key={i} style={s.teamStatRow}>
            <div style={s.teamDot}></div>
            {stat}
          </div>
        ))}
      </div>
      {member.tags.map((tag, i) => (
        <span key={i} style={{ ...s.tagHighlight, marginRight: 6 }}>{tag}</span>
      ))}
    </div>
  );
}

